CREATE TABLE IF NOT EXISTS public.logic_operator
(
    "id"          SMALLINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "value"       VARCHAR(12) NOT NULL UNIQUE,
    -- Тип оператора: LOGICAL (связка), COMPARISON (сравнение), BRACKET (скобка)
    "type"        VARCHAR(15) NOT NULL CHECK ("type" IN ('LOGICAL', 'COMPARISON', 'BRACKET')),
    -- Математический приоритет (Precedence): чем выше число, тем раньше выполняется оператор
    "precedence"  SMALLINT NOT NULL,
    -- Арность оператора: 1 - унарный (NOT/ скобки), 2 - бинарный (AND, OR, ==)
    "arity"       SMALLINT NOT NULL CHECK ("arity" IN (1, 2))
);

INSERT INTO public.logic_operator ("id", "value", "type", "precedence", "arity")
VALUES
    -- === Символы группировки (Максимальный приоритет) ===
    (1,  '(',           'BRACKET',    100, 1),
    (2,  ')',           'BRACKET',    100, 1),
    -- === Унарные операторы отрицания (Выполняются в первую очередь) ===
    (3,  'NOT',         'LOGICAL',    10,  1),
    (4,  '!',           'LOGICAL',    10,  1),
    (5,  '~',           'LOGICAL',    10,  1),
    -- === Математические операторы сравнения (Бинарные) ===
    (6,  '==',          'COMPARISON', 5,   2),
    (7,  '=',           'COMPARISON', 5,   2),
    (8,  '!=',          'COMPARISON', 5,   2),
    (9,  '<>',          'COMPARISON', 5,   2),
    (10, '<',           'COMPARISON', 5,   2),
    (11, '<=',          'COMPARISON', 5,   2),
    (12, '>',           'COMPARISON', 5,   2),
    (13, '>=',          'COMPARISON', 5,   2),
    -- === Расширенные операторы СУБД / Мониторинга (Бинарные) ===
    (14, 'IS NULL',     'COMPARISON', 5,   2),
    (15, 'IS NOT NULL', 'COMPARISON', 5,   2),
    (16, 'IN',          'COMPARISON', 5,   2),
    (17, 'NOT IN',      'COMPARISON', 5,   2),
    (18, 'BETWEEN',     'COMPARISON', 5,   2),
    (19, 'LIKE',        'COMPARISON', 5,   2),
    (20, 'ILIKE',       'COMPARISON', 5,   2),
    -- === Бинарные логические связки выражений ===
    (21, '&&',          'LOGICAL',    3,   2),
    (22, 'AND',         'LOGICAL',    3,   2),
    (23, 'XOR',         'LOGICAL',    2,   2),
    (24, '||',          'LOGICAL',    1,   2),
    (25, 'OR',          'LOGICAL',    1,   2)
ON CONFLICT ("id") DO UPDATE SET
                                 "value"      = EXCLUDED."value",
                                 "type"       = EXCLUDED."type",
                                 "precedence" = EXCLUDED."precedence",
                                 "arity"      = EXCLUDED."arity";

