    "name"      VARCHAR(255)   NOT NULL,
    "number"    INTEGER UNIQUE NOT NULL,
    "contact"   TEXT,
    "email"     TEXT,
    "directory" VARCHAR(255)
);

CREATE TABLE IF NOT EXISTS public.component
(
    "id"             BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "title"          VARCHAR  NOT NULL,
    "name_en"        VARCHAR  NOT NULL,
    "name_ru"        VARCHAR  NOT NULL,
    "plural_name_en" VARCHAR  NOT NULL,
    "plural_name_ru" VARCHAR  NOT NULL,
    "base_component" BIGINT REFERENCES public.component ("id"),
    "description_en" TEXT,
    "description_ru" TEXT,
    "access"         SMALLINT NOT NULL REFERENCES public.access ("id") ON DELETE CASCADE
);

CREATE TABLE public.param
(
    "id"             BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "title"          VARCHAR  NOT NULL,
    "name_en"        VARCHAR  NOT NULL,
    "name_ru"        VARCHAR  NOT NULL,
    "type"           SMALLINT NOT NULL REFERENCES public.var_type ("id") ON DELETE CASCADE,
    "value"          TEXT,
    "description_en" TEXT,
    "description_ru" TEXT,
    "units_en"       TEXT,
    "units_ru"       TEXT,
    "access"         SMALLINT NOT NULL REFERENCES public.access ("id") ON DELETE CASCADE,
    "saved"          BOOLEAN  NOT NULL,
    "visible"        BOOLEAN  NOT NULL
);

CREATE TABLE public.component_param
(
    "component_id" BIGINT NOT NULL REFERENCES public.component ("id"),
    "param_id"     BIGINT NOT NULL REFERENCES public.param ("id"),
    PRIMARY KEY ("component_id", "param_id")
);

