    "agent_capabilities_module_id"              BIGINT REFERENCES public.agent_capabilities_module ("id") ON DELETE CASCADE,
    "agent_capabilities_module_notification_id" BIGINT REFERENCES public.agent_capabilities_module_notification ("id") ON DELETE CASCADE,
    "agent_capabilities_module_object_id"       BIGINT REFERENCES public.agent_capabilities_module_object ("id") ON DELETE CASCADE,
    CONSTRAINT mib_ac UNIQUE NULLS NOT DISTINCT ("mib_id", "agent_capabilities_id", "agent_capabilities_module_id",
