CREATE TABLE IF NOT EXISTS public.mib_to_object_group
(
    "id"              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "mib_id"          BIGINT NOT NULL REFERENCES public.mib ("id") ON DELETE CASCADE,
    "object_group_id" BIGINT NOT NULL REFERENCES public.object_group ("id") ON DELETE CASCADE,
    CONSTRAINT mib_og UNIQUE NULLS NOT DISTINCT ("mib_id", "object_group_id")
);

CREATE TABLE IF NOT EXISTS public.mib_to_object_identifier
(
    "id"                   BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "mib_id"               BIGINT NOT NULL REFERENCES public.mib ("id") ON DELETE CASCADE,
    "object_identifier_id" BIGINT NOT NULL REFERENCES public.object_identifier ("id") ON DELETE CASCADE,
    CONSTRAINT mib_oif UNIQUE NULLS NOT DISTINCT ("mib_id", "object_identifier_id")
);

CREATE TABLE IF NOT EXISTS public.mib_to_object_identity
(
    "id"                 BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "mib_id"             BIGINT NOT NULL REFERENCES public.mib ("id") ON DELETE CASCADE,
    "object_identity_id" BIGINT NOT NULL REFERENCES public.object_identity ("id") ON DELETE CASCADE,
    CONSTRAINT mib_oit UNIQUE NULLS NOT DISTINCT ("mib_id", "object_identity_id")
);

CREATE TABLE IF NOT EXISTS public.mib_to_object_type
(
    "id"             BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "mib_id"         BIGINT NOT NULL REFERENCES public.mib ("id") ON DELETE CASCADE,
    "object_type_id" BIGINT NOT NULL REFERENCES public.object_type ("id") ON DELETE CASCADE,
    CONSTRAINT mib_ot UNIQUE NULLS NOT DISTINCT ("mib_id", "object_type_id")
);

CREATE TABLE IF NOT EXISTS public.mib_to_sequence
(
    "id"          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "mib_id"      BIGINT NOT NULL REFERENCES public.mib ("id") ON DELETE CASCADE,
    "sequence_id" BIGINT NOT NULL REFERENCES public.sequence ("id") ON DELETE CASCADE,
    CONSTRAINT mib_sec UNIQUE NULLS NOT DISTINCT ("mib_id", "sequence_id")
);

CREATE TABLE IF NOT EXISTS public.mib_to_textual_convention
(
    "id"                    BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "mib_id"                BIGINT NOT NULL REFERENCES public.mib ("id") ON DELETE CASCADE,
    "textual_convention_id" BIGINT NOT NULL REFERENCES public.textual_convention ("id") ON DELETE CASCADE,
    CONSTRAINT mib_tc UNIQUE NULLS NOT DISTINCT ("mib_id", "textual_convention_id")
);

CREATE TABLE IF NOT EXISTS public.mib_to_trap_type
(
    "id"           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "mib_id"       BIGINT NOT NULL REFERENCES public.mib ("id") ON DELETE CASCADE,
    "trap_type_id" BIGINT NOT NULL REFERENCES public.trap_type ("id") ON DELETE CASCADE,
    CONSTRAINT mib_tt UNIQUE NULLS NOT DISTINCT ("mib_id", "trap_type_id")
);

CREATE TABLE IF NOT EXISTS public.device_indicator
(
    "id"          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "description" TEXT,
    "object_id"   TEXT NOT NULL,
    "contact"     TEXT,
    "name"        TEXT,
    "location"    TEXT,
    "services"    SMALLINT,
    CONSTRAINT device_indicator_tt UNIQUE NULLS NOT DISTINCT ("description", "object_id", "contact", "name", "location", "services")
);

CREATE TABLE IF NOT EXISTS public.param_indicator
(
    "id"              BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "oid_id"          UUID REFERENCES public.oid ("id"),
    "dotter_notation" TEXT
);

CREATE TABLE IF NOT EXISTS public.mapping
(
    "id"            BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "indicator"     BIGINT   NOT NULL REFERENCES public.param_indicator ("id") ON DELETE CASCADE,
    "param"         BIGINT   NOT NULL REFERENCES public.param ("id") ON DELETE CASCADE,
    "frequency"     SMALLINT NOT NULL REFERENCES public.polling_frequency ("id") ON DELETE CASCADE,
    "value"         VARCHAR(255),
    "coefficient"   NUMERIC(38, 12),
    "enum"          JSONB,
    "position"      SMALLINT,
    "from"          BIGINT REFERENCES public.mapping ("id") ON DELETE CASCADE,
    "position_type" SMALLINT REFERENCES public.oid_type ("id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.device_component
(
    "id"             BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "model"          BIGINT NOT NULL REFERENCES public.component ("id") ON DELETE CASCADE,
    "internal_order" INTEGER DEFAULT 1,
    "parent"         BIGINT REFERENCES public.device_component ("id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.device_component_mapping
(
    "device_component_id" BIGINT NOT NULL REFERENCES public.device_component ("id") ON DELETE CASCADE,
    "mapping_id"          BIGINT NOT NULL REFERENCES public.mapping ("id") ON DELETE CASCADE,
    PRIMARY KEY ("device_component_id", "mapping_id")
);

CREATE TABLE IF NOT EXISTS public.configuration
(
    "id"                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "indicator"           BIGINT NOT NULL REFERENCES public.device_indicator ("id") ON DELETE CASCADE,
    "device_component_id" BIGINT REFERENCES public.device_component ("id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.default_configuration
(
    "id"                  BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "indicator"           BIGINT NOT NULL REFERENCES public.device_indicator ("id") ON DELETE CASCADE,
    "device_component_id" BIGINT REFERENCES public.device_component ("id") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.threshold
(
    "id"          BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "name"        VARCHAR(255) NOT NULL,
    "description" TEXT,
    "author"      VARCHAR(255),
    "created"     TIMESTAMP,
    "query"       TEXT UNIQUE  NOT NULL
);

CREATE TABLE IF NOT EXISTS public.device_snmp
(
    "host"           VARCHAR(30)  NOT NULL,
    "port"           INTEGER      NOT NULL,
    "community"      VARCHAR(255) NOT NULL,
    "version"        SMALLINT     NOT NULL REFERENCES public.version_snmp ("id") ON DELETE CASCADE,
    "login"          VARCHAR(255),
    "password"       TEXT,
    "authentication" SMALLINT     NOT NULL REFERENCES public.auth_protocol_snmp ("id") ON DELETE CASCADE,
    "privacy"        SMALLINT     NOT NULL REFERENCES public.privacy_protocol_snmp ("id") ON DELETE CASCADE,
    "id"             UUID UNIQUE  NOT NULL,
    "config"         BIGINT REFERENCES public.configuration ("id") ON DELETE CASCADE,
    PRIMARY KEY ("host", "port")
);

CREATE TABLE IF NOT EXISTS public.result
(
    "host"           VARCHAR(30) NOT NULL,
    "port"           INTEGER     NOT NULL,
    "component"      BIGINT      NOT NULL REFERENCES public.component ("id") ON DELETE CASCADE,
    "internal_order" INTEGER DEFAULT 1,
    "param"          BIGINT      NOT NULL REFERENCES public.param ("id") ON DELETE CASCADE,
    "value"          TEXT,
    PRIMARY KEY ("host", "port", "component", "internal_order", "param")
);

CREATE TABLE IF NOT EXISTS public.affected_threshold
(
    "id"        BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "host"      VARCHAR(30) NOT NULL,
    "port"      INTEGER     NOT NULL,
    "threshold" BIGINT      NOT NULL REFERENCES public.threshold ("id") ON DELETE CASCADE,
    "enabled"   BOOLEAN DEFAULT true,
    FOREIGN KEY ("host", "port") REFERENCES public.device_snmp ("host", "port") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.affected_param
(
    "id"             BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "host"           VARCHAR(30) NOT NULL,
    "port"           INTEGER     NOT NULL,
    "component"      BIGINT      NOT NULL REFERENCES public.component ("id") ON DELETE CASCADE,
    "internal_order" INTEGER DEFAULT 1,
    "param"          BIGINT      NOT NULL REFERENCES public.param ("id") ON DELETE CASCADE,
    FOREIGN KEY ("host", "port") REFERENCES public.device_snmp ("host", "port") ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.config_in_process
(
    "host"     VARCHAR(255) NOT NULL,
    "port"     INTEGER      NOT NULL,
    "protocol" SMALLINT     NOT NULL REFERENCES public.polling_protocol ("id") ON DELETE CASCADE,
    PRIMARY KEY ("host", "port", "protocol")
);